INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Managed services capability continues to operate today under new ownership (Scissero)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Robin AI no longer operates as an independent company or purchasable product as of 2026$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Company collapsed after failing to close a $50 million funding round in October 2025$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Roughly a third of staff were laid off before the company wound down$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Pricing was never fully transparent even while the company was operating$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Existing customers had to transition to new providers after the shutdown$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Is Robin AI still in business$q$, $q$No. Robin AI wound down as an independent business in late 2025 and early 2026. Its managed services team was acquired by the law firm Scissero in December 2025, and its technology and engineering team was acqui-hired by Microsoft in January 2026.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$What was Robin AI used for$q$, $q$Robin AI was an AI-powered platform that helped corporate legal and procurement teams review, redline, and negotiate contracts, combining AI analysis with human-in-the-loop lawyer review.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Who founded Robin AI$q$, $q$Robin AI was founded in 2019 by Richard Robinson, a former Clifford Chance disputes lawyer, and James Clough, a machine learning researcher from Imperial College London.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Why did Robin AI shut down$q$, $q$Robin AI's multi-year losses outpaced its revenue growth, and after a planned $50 million funding round fell through in October 2025, the company laid off about a third of its staff and entered a winding-up process.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Where can I get contract review services now that Robin AI is gone$q$, $q$Robin AI's managed services team and human-in-the-loop contract review capability now operate under the law firm Scissero, which acquired that business unit in December 2025.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$What happened to Robin AI's technology$q$, $q$Robin AI's technology and engineering team were acqui-hired by Microsoft in January 2026 to strengthen legal AI features within Microsoft Word and its productivity suite.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$How much did Robin AI cost$q$, $q$Robin AI never published detailed self-serve pricing; it used a freemium model with paid subscriptions and custom enterprise pricing, but exact figures were not publicly disclosed before the company wound down.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Where was Robin AI headquartered$q$, $q$Robin AI was headquartered in London, England, at 10 Devonshire Square.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Historical: Enterprise contract review$q$, $q$Corporate legal teams previously used Robin AI to review high volumes of commercial contracts faster by combining AI redlining with human lawyer verification.$q$, $q$In-house legal and procurement teams (historical customers)$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Historical: Contract negotiation acceleration$q$, $q$Legal teams used Robin AI's AI-suggested redlines to speed up back-and-forth contract negotiation with counterparties.$q$, $q$Legal operations and contract managers (historical customers)$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Current: Managed contract review via Scissero$q$, $q$Organizations seeking human-in-the-loop contract review today can turn to Scissero, which acquired Robin AI's managed services team and business.$q$, $q$Legal teams evaluating outsourced contract review providers in 2026$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Historical Free Tier$q$, $q$Not disclosed$q$, $q$N/A (discontinued)$q$, NULL, $q$["Limited contract review functionality","No longer available as of 2026"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Historical Paid Subscription$q$, $q$Not publicly disclosed$q$, $q$N/A (discontinued)$q$, NULL, $q$["AI contract review and redlining","Human-in-the-loop lawyer review","No longer available as of 2026"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$Historical Enterprise$q$, $q$Custom, not publicly disclosed$q$, $q$N/A (discontinued)$q$, NULL, $q$["API access","Advanced integrations","SSO and SLAs","No longer available as of 2026"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Robin AI was an AI-powered contract review and negotiation platform founded in 2019 by Richard Robinson, a former Clifford Chance disputes lawyer, and James Clough, a machine learning researcher, and headquartered in London, England. The platform combined proprietary legal AI with a human-in-the-loop team of in-house lawyers to help corporate legal and procurement teams review, redline, and negotiate contracts more efficiently, and at its peak served roughly 13 Fortune 500 companies with about $10 million in annual recurring revenue.$q$, $q$In late 2025, however, the company's losses outpaced revenue growth and a planned $50 million funding round fell through in October 2025, leading to layoffs of roughly a third of staff and a formal winding-up process. As a result, Robin AI no longer exists as an independent, purchasable product as of 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$what-happened$q$, $q$What Happened to Robin AI$q$, 2, ARRAY[$q$Robin AI's assets were split and sold in two separate transactions. In December 2025, its managed services arm, the human-in-the-loop contract review business employing around 75 staff, was acquired by the AI-forward law firm Scissero. In January 2026, Microsoft separately acqui-hired Robin AI's technology and engineering team to strengthen legal AI capabilities within Microsoft Word and its broader productivity suite.$q$, $q$As a result, businesses that previously used or were evaluating Robin AI as a standalone SaaS platform should look to Scissero for managed contract review services, or monitor how Robin AI's underlying technology may resurface inside Microsoft's products, rather than expecting to purchase or renew a 'Robin AI' subscription directly.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb49326f-7c73-43d6-b58a-39f713485eed', $q$pricing-history$q$, $q$Historical Pricing$q$, 2, ARRAY[$q$Robin AI historically used a freemium model with a limited free tier, paid subscription plans, and custom enterprise pricing that added API access, advanced integrations, single sign-on, and service-level agreements, but the company never published detailed self-serve pricing, and exact figures are not publicly available.$q$, $q$Because the company wound down as an independent business in late 2025 and early 2026, there is no current, purchasable pricing for Robin AI as a standalone product.$q$]::text[], 2);
