-- в”Ђв”Ђ Riverside в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Riverside is a remote recording and production platform for podcasts and video, offering local high-quality multi-track recording, AI editing, and publishing tools.$q$, short_description),
  pricing_model = COALESCE($q$Freemium with tiered monthly or annual subscriptions plus custom Business pricing$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans start at $24/month (Pro, billed annually)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$~90-150 employees$q$, company_size),
  headquarters = COALESCE($q$Tel Aviv, Israel (with additional offices in New York and Amsterdam)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Riverside Review 2026: Pricing, Features, and Podcast Recording Platform Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Riverside (formerly Riverside.fm) is a remote podcast and video recording platform. See 2026 pricing plans, features, pros and cons, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Riverside, formerly branded Riverside.fm and rebranded to Riverside.com, is a remote recording and content production platform used by podcasters, video creators, marketers, and businesses to record high-quality, multi-track audio and video with remote guests over the internet. The company was founded in 2020 by brothers Nadav Keyson (CEO) and Gideon Keyson (CTO), who grew up in Amsterdam before relocating to Israel, and launched the product just as the COVID-19 pandemic drove a surge in remote content creation; the company is headquartered in Tel Aviv, Israel, with additional offices in New York and Amsterdam. Riverside has raised a total of roughly $77 million across funding rounds, including a $35 million Series B in April 2022 led by Zeev Ventures, and has grown from a small team into a company with employees in the range of roughly 90 to 150 people. The platform's core technical advantage is that it records each participant's audio and video locally on their own device at up to 4K video and 48kHz audio, then uploads the files afterward, which avoids the compression artifacts and dropped frames typical of live video-call recording, and it has expanded well beyond recording into a broader production suite including AI-powered editing (text-based editing, Magic Clips for auto-generating short clips), a teleprompter, live streaming and webinar hosting, podcast and video hosting with analytics, and direct publishing to platforms like YouTube, Spotify, Apple Podcasts, Instagram, and LinkedIn. Pricing is freemium: the Free plan includes 2 hours of one-off multi-track recording at up to 720p with a Riverside watermark; the Pro plan is $24/month billed annually (or $29/month billed monthly) and includes 1 studio, 15 hours of separate track downloads, 4K video, no watermark, and the AI editing agent; the Grow plan is $34/month annually ($39 monthly) and adds social scheduling, a creator website, and multistreaming; the Webinar plan is $79/month annually ($99 monthly) and adds webinar hosting for up to 100 registrants; and the Business plan offers custom pricing with unlimited studios, unlimited track downloads, SSO, SOC 2 and ISO 27001 compliance, and a dedicated customer success manager. Riverside is commonly compared to tools like SquadCast, Zencastr, and StreamYard, and it is distinct from the animation tool Rive (rive.app), despite the similar-sounding name.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'dc81b714-5cd0-41b9-8464-c9eca6e97648';

