  pricing_model = COALESCE($q$Per-developer-per-month subscription plus custom enterprise pricing$q$, pricing_model),
  starting_price = COALESCE($q$From $24 per developer per month (Teams plan)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$~20-30 employees$q$, company_size),
  headquarters = COALESCE($q$Dublin, Ireland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Roadie Review 2026: Pricing, Features, and Backstage Developer Portal Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Roadie is a hosted Backstage-based internal developer portal. See 2026 pricing, features, pros and cons, and how it compares to self-hosting Backstage.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Roadie is a fully hosted and managed internal developer portal built on top of Spotify's open-source Backstage framework, letting engineering organizations get a software catalog, technical documentation hub, and developer self-service platform without the overhead of running and maintaining Backstage themselves. The company was founded in 2020, timed to start offering Backstage as a hosted service as soon as the open-source framework was released, and operates as a fully remote, headquartered-in-Dublin, Ireland company with a small team generally estimated in the range of roughly 20 to 30 employees. Roadie describes itself as the second-largest contributor to the Backstage project after Spotify itself, and its customers include companies such as Netlify, Snyk, Contentful, and MyFitnessPal. The core product provides a Backstage-compatible software catalog (tracking services, APIs, and ownership across an engineering organization), TechDocs and API specification hosting, self-service automation templates ('software templates' in Backstage terminology) for scaffolding new services, access to more than 75 open-source Backstage plugins, single sign-on, and more recently RAG-based AI search and MCP (Model Context Protocol) server access for connecting AI coding agents to the organization's software catalog context. Roadie also sells a separate 'Enterprise Context' product, an integration-powered data layer that pulls together data from many pre-built and custom sources into a permissioned context bundle that can be used standalone or bundled with the developer portal, aimed at powering AI agents with reliable organizational context. Pricing is per 'contributing developer' (engineers who write code tracked in the catalog; non-coding users can access it for free), with the Teams plan priced at $24 per developer per month for organizations of roughly 50 to 150 developers with unlimited catalog entities, while the Growth plan and Enterprise Context product use custom pricing that adds SLAs, custom private Backstage plugins, REST API access, advanced search, secure on-premise connections, usage analytics dashboards, and custom role-based access control for larger organizations. Roadie has raised roughly $3.7 million in funding from investors including Boldstart Ventures and Firstminute Capital, and it is positioned against alternatives like self-hosting Backstage in-house, Spotify's own commercial Backstage offering (Portal), Cortex, and OpsLevel in the internal developer platform category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd2f52a6e-f44d-4cf6-8f6a-17030432b63d';

